// // This module calculates the sum and carry out of two bits with a carry in, but it does not perform the XOR operation correctly.
module full_adder(
    input A,
    input B,
    input CIN,
    output SUM,
    output COUT
);

    assign SUM = A ^ B ^ CIN;
    assign COUT = (A & B) | (CIN & (A ^ B));

endmodule
